// Test: ideal sailing conditions should return green level
async function testComputeSeaStatusGreen() {
  const result = functions.call('computeSeaStatus', {
    windSpeed: 12,      // pleasant sailing wind
    windGusts: 15,      // mild gusts
    waveHeight: 0.8,    // calm seas
    precipitation: 0,   // dry
    pressure: 1015,     // normal pressure
    cloudCover: 20      // partly cloudy
  });

  assertEquals(result.level, 'green', 'Ideal conditions should be green');
  assertEquals(result.label, 'Good to Go');
  assert(result.score >= 70, 'Green score should be >= 70, got ' + result.score);
  assert(Array.isArray(result.reasons), 'Reasons should be an array');
}
